// Parse RSS XML and extract items
const items = $input.all();
console.log(`=== RSS Feed Analysis ===`);
console.log(`Total inputs received: ${items.length}`);

const results = [];

for (const item of items) {
  const xmlData = item.json.data || item.json;
  console.log(`XML Data type: ${typeof xmlData}`);
  console.log(`XML Data sample: ${JSON.stringify(xmlData).substring(0, 200)}...`);

  // Simple XML parsing for RSS items
  const xmlString = typeof xmlData === 'string' ? xmlData : JSON.stringify(xmlData);

  // Extract RSS items using regex (basic parsing)
  const itemMatches = xmlString.match(/<item[^>]*>([\s\S]*?)<\/item>/gi) || [];
  console.log(`Found ${itemMatches.length} RSS items`);

  for (let i = 0; i < Math.min(itemMatches.length, 3); i++) {
    const itemXml = itemMatches[i];

    // Extract title
    const titleMatch = itemXml.match(/<title[^>]*><!\[CDATA\[(.*?)\]\]><\/title>/i) || 
                      itemXml.match(/<title[^>]*>(.*?)<\/title>/i);
    const title = titleMatch ? titleMatch[1].trim() : 'No title';

    // Extract description
    const descMatch = itemXml.match(/<description[^>]*><!\[CDATA\[(.*?)\]\]><\/description>/i) || 
                     itemXml.match(/<description[^>]*>(.*?)<\/description>/i);
    const description = descMatch ? descMatch[1].trim() : 'No description';

    // Extract link
    const linkMatch = itemXml.match(/<link[^>]*>(.*?)<\/link>/i);
    const link = linkMatch ? linkMatch[1].trim() : 'No link';

    // Extract pubDate
    const dateMatch = itemXml.match(/<pubDate[^>]*>(.*?)<\/pubDate>/i);
    const pubDate = dateMatch ? dateMatch[1].trim() : 'No date';

    console.log(`\n--- Item ${i+1} ---`);
    console.log(`Title: ${title}`);
    console.log(`Description: ${description.substring(0, 100)}...`);
    console.log(`Link: ${link}`);
    console.log(`PubDate: ${pubDate}`);

    results.push({
      json: {
        item_number: i + 1,
        title: title,
        description: description,
        link: link,
        pubDate: pubDate,
        xml_sample: itemXml.substring(0, 300) + '...'
      }
    });
  }
}

console.log(`\n=== Analysis Complete ===`);
console.log(`Returning ${results.length} parsed items`);
return results;
